class Solution:
    def maxSumSubmatrix(self, matrix, k):
        import bisect
        m = len(matrix)
        n = len(matrix[0])
        best = float('-inf')
        for left in range(n):
            row_sum = [0] * m
            for right in range(left, n):
                for i in range(m):
                    row_sum[i] += matrix[i][right]
                prefixes = [0]
                cur = 0
                for v in row_sum:
                    cur += v
                    idx = bisect.bisect_left(prefixes, cur - k)
                    if idx < len(prefixes):
                        best = max(best, cur - prefixes[idx])
                    bisect.insort(prefixes, cur)
        return best

