var maxSumSubmatrix = function(matrix, k) {
    const m = matrix.length, n = matrix[0].length;
    let best = -Infinity;
    const lowerBound = (arr, target) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const mid = (lo + hi) >> 1; if (arr[mid] < target) lo = mid + 1; else hi = mid; }
        return lo;
    };
    for (let left = 0; left < n; left++) {
        const rowSum = new Array(m).fill(0);
        for (let right = left; right < n; right++) {
            for (let i = 0; i < m; i++) rowSum[i] += matrix[i][right];
            const prefixes = [0];
            let cur = 0;
            for (const v of rowSum) {
                cur += v;
                const idx = lowerBound(prefixes, cur - k);
                if (idx < prefixes.length) best = Math.max(best, cur - prefixes[idx]);
                const ins = lowerBound(prefixes, cur);
                prefixes.splice(ins, 0, cur);
            }
        }
    }
    return best;
};
